// ============================================================
// STEP 1: SEED INTERNAL SALES & PRODUCT DATA
// In production: replace with DB query, Google Sheets, or CRM API
// ============================================================

const productData = {
  product_id: $json.body?.product_id || 'PROD-001',
  product_name: $json.body?.product_name || 'SaaS Pro Plan',
  current_price: parseFloat($json.body?.current_price || 49.00),
  cogs: parseFloat($json.body?.cogs || 12.00),           // Cost of Goods Sold
  target_margin_pct: parseFloat($json.body?.target_margin || 0.55), // 55% target
  min_acceptable_margin: 0.30,                            // floor
  currency: $json.body?.currency || 'USD',

  // Historical sales data (last 90 days by price point)
  sales_history: [
    { price: 39.00, units_sold: 420, period_days: 30, traffic: 8200, conversions: 420 },
    { price: 45.00, units_sold: 310, period_days: 30, traffic: 7900, conversions: 310 },
    { price: 49.00, units_sold: 275, period_days: 30, traffic: 8100, conversions: 275 }
  ],

  // Current demand signals
  demand_signals: {
    monthly_traffic: 8100,
    product_page_views: 5200,
    cart_abandonment_rate: 0.68,
    avg_session_duration_sec: 142,
    search_trend_index: 74,       // 0-100, higher = rising demand
    seasonal_multiplier: 1.05,    // slight seasonal uplift
    repeat_purchase_rate: 0.22
  },

  // Simulation price points to test
  price_points_to_test: [35, 39, 42, 45, 49, 55, 59, 65, 69, 75]
};

return [{ json: productData }];

// ============================================================
// STEP 2: NORMALIZE COMPETITOR DATA
// Handles API failures gracefully with fallback mock data
// ============================================================

const internalData = $node['Load Internal Data'].json;

// Mock competitor data (fallback if API fails or for demo)
const mockCompetitors = [
  { name: 'Competitor Alpha',  price: 45.00, currency: 'USD', plan: 'Pro',  rating: 4.2, last_seen: new Date().toISOString() },
  { name: 'Competitor Beta',   price: 39.00, currency: 'USD', plan: 'Pro',  rating: 3.8, last_seen: new Date().toISOString() },
  { name: 'Competitor Gamma',  price: 59.00, currency: 'USD', plan: 'Pro',  rating: 4.5, last_seen: new Date().toISOString() },
  { name: 'Competitor Delta',  price: 52.00, currency: 'USD', plan: 'Pro',  rating: 4.0, last_seen: new Date().toISOString() },
  { name: 'Competitor Epsilon',price: 29.00, currency: 'USD', plan: 'Pro',  rating: 3.2, last_seen: new Date().toISOString() }
];

// Use live data if available, else fall back
let competitors = mockCompetitors;
try {
  const raw = $json;
  if (raw && raw.products && Array.isArray(raw.products)) {
    competitors = raw.products.map(p => ({
      name: p.vendor_name || 'Unknown',
      price: parseFloat(p.price) || 0,
      currency: p.currency || 'USD',
      plan: p.plan_name || 'Standard',
      rating: parseFloat(p.rating) || 0,
      last_seen: p.updated_at || new Date().toISOString()
    })).filter(c => c.price > 0);
  }
} catch(e) {
  // Use mock data silently
}

// Filter outliers (IQR method)
const prices = competitors.map(c => c.price).sort((a, b) => a - b);
const q1 = prices[Math.floor(prices.length * 0.25)];
const q3 = prices[Math.floor(prices.length * 0.75)];
const iqr = q3 - q1;
const validCompetitors = competitors.filter(c => 
  c.price >= (q1 - 1.5 * iqr) && c.price <= (q3 + 1.5 * iqr)
);

// Market statistics
const validPrices = validCompetitors.map(c => c.price);
const marketMin    = Math.min(...validPrices);
const marketMax    = Math.max(...validPrices);
const marketMean   = validPrices.reduce((a,b) => a+b, 0) / validPrices.length;
const sortedValid  = [...validPrices].sort((a,b) => a-b);
const marketMedian = sortedValid.length % 2 === 0
  ? (sortedValid[sortedValid.length/2 - 1] + sortedValid[sortedValid.length/2]) / 2
  : sortedValid[Math.floor(sortedValid.length/2)];

// Our pricing percentile in the market
const ourPrice = internalData.current_price;
const belowUs = validPrices.filter(p => p < ourPrice).length;
const ourPercentile = Math.round((belowUs / validPrices.length) * 100);

let positionLabel;
if (ourPercentile <= 25)      positionLabel = 'UNDERPRICED';
else if (ourPercentile <= 50) positionLabel = 'MARKET_AVERAGE_LOW';
else if (ourPercentile <= 75) positionLabel = 'MARKET_AVERAGE_HIGH';
else                          positionLabel = 'PREMIUM_PRICED';

return [{
  json: {
    ...internalData,
    competitor_analysis: {
      competitors: validCompetitors,
      outliers_removed: competitors.length - validCompetitors.length,
      market_min: parseFloat(marketMin.toFixed(2)),
      market_max: parseFloat(marketMax.toFixed(2)),
      market_mean: parseFloat(marketMean.toFixed(2)),
      market_median: parseFloat(marketMedian.toFixed(2)),
      our_percentile: ourPercentile,
      position_label: positionLabel,
      data_freshness: new Date().toISOString()
    }
  }
}];

// ============================================================
// STEP 3: DEMAND ELASTICITY MODELING
// Calculates Price Elasticity of Demand (PED) from sales history
// Uses linear regression + weighted conversion analysis
// ============================================================

const data = $json;
const history = data.sales_history;
const signals = data.demand_signals;

// --- 3a. Compute conversion rates from history ---
const historyWithCR = history.map(h => ({
  ...h,
  conversion_rate: h.conversions / h.traffic,
  daily_units: h.units_sold / h.period_days,
  revenue: h.price * h.units_sold
}));

// --- 3b. Linear Regression for Price vs Conversion Rate ---
// y = conversion_rate, x = price
const n = historyWithCR.length;
const sumX  = historyWithCR.reduce((s, h) => s + h.price, 0);
const sumY  = historyWithCR.reduce((s, h) => s + h.conversion_rate, 0);
const sumXY = historyWithCR.reduce((s, h) => s + h.price * h.conversion_rate, 0);
const sumX2 = historyWithCR.reduce((s, h) => s + h.price * h.price, 0);

const slope     = (n * sumXY - sumX * sumY) / (n * sumX2 - sumX * sumX);
const intercept = (sumY - slope * sumX) / n;

// --- 3c. Point Price Elasticity of Demand (PED) ---
// PED = (dQ/Q) / (dP/P) approximated from regression slope
const basePrice = data.current_price;
const baseCR    = intercept + slope * basePrice;
const ped       = (slope * basePrice) / baseCR;  // dimensionless

// --- 3d. Demand quality score (0-1) ---
const demandScore = (
  (signals.search_trend_index / 100) * 0.3 +
  (1 - signals.cart_abandonment_rate) * 0.4 +
  (signals.avg_session_duration_sec / 300) * 0.2 +
  signals.seasonal_multiplier * 0.1
) * signals.seasonal_multiplier;

// --- 3e. Demand sensitivity label ---
let elasticityLabel;
if (Math.abs(ped) > 2.0)      elasticityLabel = 'HIGHLY_ELASTIC';    // very price sensitive
else if (Math.abs(ped) > 1.0) elasticityLabel = 'ELASTIC';           // moderately sensitive
else if (Math.abs(ped) > 0.5) elasticityLabel = 'INELASTIC';         // less sensitive
else                           elasticityLabel = 'HIGHLY_INELASTIC';  // price insensitive

return [{
  json: {
    ...data,
    elasticity_model: {
      regression_slope: parseFloat(slope.toFixed(6)),
      regression_intercept: parseFloat(intercept.toFixed(6)),
      price_elasticity_of_demand: parseFloat(ped.toFixed(3)),
      elasticity_label: elasticityLabel,
      base_conversion_rate: parseFloat(baseCR.toFixed(4)),
      demand_quality_score: parseFloat(Math.min(demandScore, 1).toFixed(3)),
      history_with_cr: historyWithCR,
      model_note: 'Linear regression on 90-day historical data. Min 6 data points recommended for production.'
    }
  }
}];

// ============================================================
// STEP 4: PRICE SIMULATION ENGINE
// Tests every candidate price point and projects key metrics
// ============================================================
console.log('INPUT:', JSON.stringify({
  price_points: $json.price_points_to_test,
  cogs: $json.cogs,
  current_price: $json.current_price,
  elasticity_model: $json.elasticity_model,
  competitor_analysis: $json.competitor_analysis
}));


const data = $json;
const model = data.elasticity_model;
const signals = data.demand_signals;
const cogs = data.cogs;
const pricePoints = data.price_points_to_test;

function predictCR(price) {
  const raw = model.regression_intercept + model.regression_slope * price;
  const adjusted = raw * model.demand_quality_score * data.demand_signals.seasonal_multiplier;
  return Math.max(0.005, Math.min(0.25, adjusted));
}

const simulations = (pricePoints || []).map(price => {
  const cr           = predictCR(price);
  const monthly_vol  = Math.round(signals.monthly_traffic * cr);
  const revenue      = parseFloat((price * monthly_vol).toFixed(2));
  const gross_profit = parseFloat(((price - cogs) * monthly_vol).toFixed(2));
  const margin_pct   = parseFloat(((price - cogs) / price).toFixed(4));
  const profit_score = gross_profit * (1 - Math.max(0, data.target_margin_pct - margin_pct));
  const medianDiff   = Math.abs(price - data.competitor_analysis.market_median);
  const comp_score   = Math.max(0, 1 - medianDiff / data.competitor_analysis.market_median);
  const balanced_score = (profit_score / 10000) * 0.60 + comp_score * 0.25 + cr * 100 * 0.15;

  let risk_level;
  if (margin_pct < data.min_acceptable_margin)                  risk_level = 'CRITICAL';
  else if (margin_pct < data.target_margin_pct - 0.10)         risk_level = 'HIGH';
  else if (price > data.competitor_analysis.market_max * 1.1)  risk_level = 'HIGH';
  else if (price < data.competitor_analysis.market_min * 0.85) risk_level = 'MEDIUM';
  else                                                           risk_level = 'LOW';

  return {
    price,
    predicted_cr: parseFloat(cr.toFixed(4)),
    monthly_units: monthly_vol,
    monthly_revenue: revenue,
    monthly_gross_profit: gross_profit,
    margin_pct: parseFloat((margin_pct * 100).toFixed(1)),
    profit_score: parseFloat(profit_score.toFixed(2)),
    competitive_score: parseFloat(comp_score.toFixed(3)),
    balanced_score: parseFloat(balanced_score.toFixed(4)),
    risk_level,
    vs_current_revenue: parseFloat((revenue - (data.current_price * signals.monthly_traffic * model.base_conversion_rate)).toFixed(2))
  };
});

// Fallback sim so reduce never operates on an empty array
const fallbackSim = {
  price: data.current_price || 0,
  predicted_cr: 0, monthly_units: 0, monthly_revenue: 0,
  monthly_gross_profit: 0, margin_pct: 0, profit_score: 0,
  competitive_score: 0, balanced_score: 0,
  risk_level: 'CRITICAL', vs_current_revenue: 0
};

const simsForReduce = simulations.length > 0 ? simulations : [fallbackSim];
const validSims     = simulations.filter(s => s.risk_level !== 'CRITICAL');

const profitOptimal  = simsForReduce.reduce((best, s) =>
  s.monthly_gross_profit > best.monthly_gross_profit ? s : best
);
const balancedOptimal = validSims.length > 0
  ? validSims.reduce((best, s) => s.balanced_score > best.balanced_score ? s : best)
  : profitOptimal;

const safeRange = simulations.filter(s =>
  s.risk_level === 'LOW' && s.margin_pct >= data.min_acceptable_margin * 100
);
const safeMin = safeRange.length ? Math.min(...safeRange.map(s => s.price)) : null;
const safeMax = safeRange.length ? Math.max(...safeRange.map(s => s.price)) : null;

return [{
  json: {
    ...data,
    simulations,
    price_recommendation: {
      profit_maximizing_price: profitOptimal.price,
      balanced_growth_price:   balancedOptimal.price,
      recommended_price:       balancedOptimal.price,
      safe_range_min:          safeMin,
      safe_range_max:          safeMax,
      risky_above:             data.competitor_analysis.market_max * 1.1,
      risky_below:             data.cogs / (1 - data.min_acceptable_margin),
      profit_optimal_sim:      profitOptimal,
      balanced_optimal_sim:    balancedOptimal
    }
  }
}];

// ============================================================
// STEP 5: CONFIDENCE SCORING & STRUCTURED PAYLOAD
// Packages everything for the AI summarization layer
// ============================================================
console.log('REC:', JSON.stringify($json.price_recommendation));
const data = $json;
const rec  = data.price_recommendation || {};
const comp = data.competitor_analysis  || {};
const model = data.elasticity_model    || {};

const currentSim = (data.simulations || []).find(s => s.price === data.current_price)
  || { monthly_revenue: 0, monthly_gross_profit: 0 };

const dataPoints          = (data.sales_history || []).length;
const elasticityConfidence = Math.min(dataPoints / 6, 1);
const marketConfidence     = Math.min((comp.competitors || []).length / 5, 1);
const demandConfidence     = model.demand_quality_score || 0;
const overallConfidence    = Math.round(
  (elasticityConfidence * 0.40 + marketConfidence * 0.30 + demandConfidence * 0.30) * 100
);

// Null-safe: fall back to a zero-state object if balanced_optimal_sim is missing
const balOptSim = rec.balanced_optimal_sim || {
  monthly_revenue: 0, monthly_gross_profit: 0,
  margin_pct: 0, risk_level: 'UNKNOWN'
};

const revDelta      = parseFloat((balOptSim.monthly_revenue    - currentSim.monthly_revenue).toFixed(2));
const profDelta     = parseFloat((balOptSim.monthly_gross_profit - currentSim.monthly_gross_profit).toFixed(2));
const priceDelta    = parseFloat(((rec.recommended_price || 0) - (data.current_price || 0)).toFixed(2));
const priceDeltaPct = data.current_price
  ? parseFloat(((priceDelta / data.current_price) * 100).toFixed(1))
  : 0;

const analysisPayload = {
  product: {
    id:                data.product_id,
    name:              data.product_name,
    current_price:     data.current_price,
    cogs:              data.cogs,
    target_margin_pct: (data.target_margin_pct || 0) * 100
  },
  market: {
    position:         comp.position_label,
    our_percentile:   comp.our_percentile,
    market_median:    comp.market_median,
    market_range:     `$${comp.market_min} - $${comp.market_max}`,
    competitor_count: (comp.competitors || []).length
  },
  elasticity: {
    ped:        model.price_elasticity_of_demand,
    sensitivity: model.elasticity_label,
    base_cr:    `${((model.base_conversion_rate || 0) * 100).toFixed(2)}%`
  },
  recommendation: {
    recommended_price:            rec.recommended_price,
    profit_maximizing_price:      rec.profit_maximizing_price,
    safe_range:                   `$${rec.safe_range_min} - $${rec.safe_range_max}`,
    predicted_monthly_revenue:    balOptSim.monthly_revenue,
    predicted_monthly_profit:     balOptSim.monthly_gross_profit,
    predicted_margin:             `${balOptSim.margin_pct}%`,
    revenue_delta_vs_current:     revDelta,
    profit_delta_vs_current:      profDelta,
    price_change:                 `${priceDelta >= 0 ? '+' : ''}$${priceDelta} (${priceDeltaPct >= 0 ? '+' : ''}${priceDeltaPct}%)`,
    confidence_score:             overallConfidence,
    risk_level:                   balOptSim.risk_level
  },
  simulation_summary: (data.simulations || []).map(s => ({
    price:          s.price,
    margin:         `${s.margin_pct}%`,
    monthly_profit: s.monthly_gross_profit,
    risk:           s.risk_level
  })),
  alerts: [
    ...(comp.position_label === 'UNDERPRICED'         ? ['Product appears underpriced relative to market'] : []),
    ...(model.elasticity_label === 'HIGHLY_ELASTIC'   ? ['Demand is highly price sensitive - proceed with increases carefully'] : []),
    ...(balOptSim.margin_pct < (data.target_margin_pct || 0) * 100 ? ['Recommended price is below target margin'] : []),
    ...(priceDeltaPct > 15                            ? ['Recommended price increase >15% - consider phased rollout'] : [])
  ]
};

return [{ json: { ...data, analysis_payload: analysisPayload, confidence_score: overallConfidence } }];

// ============================================================
// STEP 6: PARSE AI RESPONSE + VALIDATE
// Extracts Claude's JSON insight, falls back gracefully
// ============================================================

const prevData = $node['Build Analysis Payload'].json;
const aiResponse = $json;

let aiInsights = null;
let aiError = null;

try {
  const content = aiResponse.content?.[0]?.text || '';
  // Strip any accidental markdown fences
  const clean = content.replace(/```json|```/g, '').trim();
  aiInsights = JSON.parse(clean);
} catch (e) {
  aiError = `AI parse error: ${e.message}`;
  // Graceful fallback
  const rec = prevData.price_recommendation;
  const balSim = rec.balanced_optimal_sim;
  aiInsights = {
    executive_summary: `Based on market analysis and demand modeling, a price of $${rec.recommended_price} is recommended for ${prevData.product_name}. This optimizes for balanced growth given current market conditions.`,
    market_insight: `Product is positioned at the ${prevData.competitor_analysis.our_percentile}th percentile of competitor pricing. Market median is $${prevData.competitor_analysis.market_median}.`,
    demand_insight: `Demand shows ${prevData.elasticity_model.elasticity_label.toLowerCase().replace('_', ' ')} characteristics with a PED of ${prevData.elasticity_model.price_elasticity_of_demand}.`,
    primary_recommendation: {
      price: rec.recommended_price,
      rationale: 'Derived from profit simulation engine and market positioning analysis.',
      expected_impact: `Projected monthly profit: $${balSim.monthly_gross_profit} at ${balSim.margin_pct}% margin.`,
      implementation: balSim.risk_level === 'LOW' ? 'Can be implemented immediately.' : 'Consider A/B testing before full rollout.'
    },
    alternative_strategy: {
      price: rec.profit_maximizing_price,
      name: 'Profit Maximization Strategy',
      rationale: 'Choose if margin improvement is the primary goal.',
      trade_off: 'Higher margin but likely lower conversion volume.'
    },
    risks: prevData.analysis_payload.alerts.length > 0 ? prevData.analysis_payload.alerts : ['Monitor conversion rate post-change', 'Watch competitor response'],
    opportunities: ['Optimize packaging at new price point', 'Test annual plan pricing'],
    monitoring_kpis: ['Conversion rate (target: maintain within 10% of baseline)', 'Monthly gross profit', 'Competitor price gap'],
    one_line_verdict: `Price at $${rec.recommended_price} to maximize balanced growth.`
  };
}

return [{
  json: {
    ...prevData,
    ai_insights: aiInsights,
    ai_error: aiError,
    report_generated_at: new Date().toISOString(),
    run_id: `RUN-${Date.now()}`
  }
}];

// ============================================================
// STEP 7: ALERT TRIGGER EVALUATION
// Checks if any alert conditions are met
// ============================================================

const data = $json;
const comp = data.competitor_analysis;
const rec = data.price_recommendation;
const prevRec = null; // In production: load from DB/Sheets for comparison

const alerts = [];

// Competitor significantly below us
const cheapestComp = comp.competitors.reduce((min, c) => c.price < min.price ? c : min, comp.competitors[0]);
if (cheapestComp && cheapestComp.price < data.current_price * 0.75) {
  alerts.push({
    type: 'COMPETITOR_UNDERCUT',
    severity: 'HIGH',
    message: `${cheapestComp.name} is pricing at $${cheapestComp.price} — ${Math.round((1 - cheapestComp.price/data.current_price)*100)}% below you. Review positioning.`
  });
}

// Margin below threshold
const currentSim = data.simulations.find(s => s.price === data.current_price);
if (currentSim && currentSim.margin_pct < data.min_acceptable_margin * 100) {
  alerts.push({
    type: 'MARGIN_CRITICAL',
    severity: 'CRITICAL',
    message: `Current margin of ${currentSim.margin_pct}% is below the minimum acceptable threshold of ${data.min_acceptable_margin*100}%.`
  });
}

// Demand signal warning
if (data.demand_signals.cart_abandonment_rate > 0.75) {
  alerts.push({
    type: 'HIGH_ABANDONMENT',
    severity: 'MEDIUM',
    message: `Cart abandonment rate is ${(data.demand_signals.cart_abandonment_rate*100).toFixed(0)}% — significantly above average. Price may be a conversion barrier.`
  });
}

// Large recommended change
const priceDelta = Math.abs(rec.recommended_price - data.current_price);
if (priceDelta > data.current_price * 0.20) {
  alerts.push({
    type: 'LARGE_PRICE_CHANGE',
    severity: 'MEDIUM',
    message: `Recommended change of $${priceDelta.toFixed(2)} (${((priceDelta/data.current_price)*100).toFixed(0)}%) is significant. Consider phased rollout.`
  });
}

return [{
  json: {
    ...data,
    active_alerts: alerts,
    has_critical_alert: alerts.some(a => a.severity === 'CRITICAL'),
    has_high_alert: alerts.some(a => a.severity === 'HIGH')
  }
}];

// ============================================================
// STEP 8: FORMAT GOOGLE SHEETS ROW
// Flattens all data into a single Sheets-compatible row
// ============================================================
const d = $json;
const rec = d.price_recommendation || {};
const balSim = rec.balanced_optimal_sim || {
  monthly_revenue: 0, monthly_gross_profit: 0,
  margin_pct: 0, predicted_cr: 0, risk_level: 'UNKNOWN'
};
const insights = d.ai_insights || {};
const comp = d.competitor_analysis || {};

const sheetsRow = {
  // Meta
  run_id:        d.run_id,
  timestamp:     d.report_generated_at,
  product_id:    d.product_id,
  product_name:  d.product_name,
  // Current state
  current_price:      d.current_price,
  current_position:   comp.position_label,
  current_percentile: comp.our_percentile,
  // Market
  market_median:    comp.market_median,
  market_min:       comp.market_min,
  market_max:       comp.market_max,
  competitor_count: (comp.competitors || []).length,
  // Recommendation
  recommended_price:  rec.recommended_price,
  profit_max_price:   rec.profit_maximizing_price,
  safe_range_min:     rec.safe_range_min,
  safe_range_max:     rec.safe_range_max,
  // Predicted outcomes
  predicted_monthly_revenue:  balSim.monthly_revenue,
  predicted_monthly_profit:   balSim.monthly_gross_profit,
  predicted_margin_pct:       balSim.margin_pct,
  predicted_conversion_rate:  ((balSim.predicted_cr || 0) * 100).toFixed(2),
  // Elasticity
  price_elasticity: (d.elasticity_model || {}).price_elasticity_of_demand,
  elasticity_label: (d.elasticity_model || {}).elasticity_label,
  // Confidence
  confidence_score: d.confidence_score,
  risk_level:       balSim.risk_level,
  // AI insights
  executive_summary:  insights.executive_summary || '',
  one_line_verdict:   insights.one_line_verdict || '',
  primary_rationale:  insights.primary_recommendation?.rationale || '',
  top_risk:           insights.risks?.[0] || '',
  top_opportunity:    insights.opportunities?.[0] || '',
  // Alerts
  alert_count:  (d.active_alerts || []).length,
  alert_types:  (d.active_alerts || []).map(a => a.type).join(', ')
};

return [{ json: { ...d, ...sheetsRow } }];

// ============================================================
// STEP 9: COMPOSE EMAIL REPORT (HTML)
// Rich HTML email with full analysis
// ============================================================

const d = $json;
const rec = d.price_recommendation || {};
const balSim = rec.balanced_optimal_sim || {
  monthly_revenue: 0, monthly_gross_profit: 0,
  margin_pct: 0, predicted_cr: 0, risk_level: 'UNKNOWN'
};
const insights = d.ai_insights || {};
const comp = d.competitor_analysis || {};

const alertsHtml = (d.active_alerts || []).length > 0
  ? (d.active_alerts || []).map(a => `<tr><td style='color:${a.severity==='CRITICAL'?'#dc2626':a.severity==='HIGH'?'#ea580c':'#ca8a04'};font-weight:600'>${a.severity}</td><td>${a.message}</td></tr>`).join('')
  : '<tr><td colspan="2">No alerts triggered</td></tr>';

const simTableHtml = (d.simulations || []).map(s => {
  const isRec = s.price === rec.recommended_price;
  const bgColor = isRec ? '#dbeafe' : s.risk_level === 'CRITICAL' ? '#fee2e2' : 'white';
  return `<tr style='background:${bgColor}'>
    <td>$${s.price}${isRec ? ' ⭐' : ''}</td>
    <td>${s.margin_pct}%</td>
